CREATE DEFINER=`root`@`localhost` PROCEDURE `delete_order_product`(
	order_id_p INT,
    product_id_p INT
)
BEGIN
	DELETE FROM contains
		WHERE order_id = order_id_p
		AND product_id = product_id_p;

	DELETE FROM customer_order
		WHERE order_id = order_id_p;
END ;;
